  // ============ ARABIC FAQ ============
  faqAr: [
    { q: "هل يمكن للمرأة الحج بدون محرم؟", a: "الجمهور يشترط المحرم. بعض العلماء أجازوا الحج مع مجموعة نساء ثقات. الأفضل أن يكون معها محرم." },
    { q: "ماذا لو جاءني الحيض أثناء الحج؟", a: "الحيض لا يمنع الحج. افعلي كل شيء إلا الطواف (انتظري الطهر أو تناولي حبوب تأخير). طواف الوداع يسقط عن الحائض." },
    { q: "هل يمكن استخدام الهاتف أثناء الطواف؟", a: "نعم، لكن لا تنشغلوا بالصور والسيلفي. بعض الصور تذكارية لا بأس، ثم أطفئوا الهاتف وتفرغوا للدعاء." },
    { q: "ماذا لو ضللت الطريق في الحج؟", a: "لا تقلقوا. اتبعوا الحشود (الجميع يذهب لنفس المكان). اسألوا الشرطة أو المتطوعين. احملوا بطاقة فندقكم دائماً." },
    { q: "هل يجب الحلق أم يمكن التقصير؟", a: "الحلق أفضل للرجال (النبي ﷺ دعا للمحلقين ٣ مرات). التقصير جائز. النساء تقصّ فقط ١-٢ سم." },
    { q: "كم يكلف الحج تقريباً؟", a: "من فرنسا: ٧٠٠٠-١٥٠٠٠ يورو حسب مستوى الراحة. اقتصادي ~٧٠٠٠€، متوسط ~٩٠٠٠€، فاخر ~١٥٠٠٠€." },
    { q: "هل يمكنني أخذ أدوية أثناء الإحرام؟", a: "نعم، الأدوية مسموحة بالكامل. الحفاظ على صحتكم واجب شرعي. لا تتوقفوا عن أي علاج." },
    { q: "ماذا لو فاتني الوقوف بعرفة؟", a: "إذا لم تقفوا بعرفة ولو لحظة بين الزوال والفجر، فاتكم الحج. يتحول إلى عمرة. لذلك هذا الركن لا يُفوَّت أبداً." },
    { q: "هل أصلي القصر أم الكاملة في منى؟", a: "صلوا قصراً (٤ → ٢ ركعات) لأنكم مسافرون. لا تجمعوا يوم ٨ ذي الحجة. اجمعوا يوم عرفة (الظهر + العصر)." },
    { q: "هل يمكن الطواف في الطابق العلوي أو السطح؟", a: "نعم، الطواف صحيح في جميع الطوابق. السطح أقل ازدحاماً لكن المسافة أطول." },
    { q: "هل يجب رمي الجمرات بنفسي؟", a: "الأصل أن ترموا بأنفسكم. يجوز التوكيل للمريض والعاجز وكبير السن والمرأة الحامل." },
    { q: "ماذا لو نسيت إحدى مناسك الحج؟", a: "حسب المنسك: إن كان ركناً (طواف الإفاضة) يجب إتمامه. إن كان واجباً (مبيت منى) تجبره بذبح. إن كان سنة فلا شيء عليكم." },
    { q: "هل يمكنني استخدام العطر بعد الإحرام؟", a: "لا! العطر محرم في الإحرام. لا صابون معطر ولا كريم معطر. يجوز بعد التحلل الأول." },
    { q: "كيف أحجز الروضة الشريفة في المدينة؟", a: "عبر تطبيق نسك. حجز مسبق بـ QR code. ١٠ دقائق للزيارة. مرة واحدة في السنة. باب ٣٧ (رجال) وباب ٢٥ (نساء)." },
    { q: "هل يجوز الحج عن الوالدين المتوفين؟", a: "نعم، يجوز الحج عن الميت وعن العاجز عجزاً دائماً. يشترط أن تكونوا قد حججتم عن أنفسكم أولاً." },
    { q: "ما الفرق بين التمتع والقران والإفراد؟", a: "التمتع: عمرة ثم تحلل ثم حج (الأفضل). القران: عمرة وحج معاً بإحرام واحد. الإفراد: حج فقط بدون عمرة." },
    { q: "هل يمكنني غسل ملابس الإحرام؟", a: "نعم، يجوز غسلها بصابون غير معطر. يجوز تغييرها أيضاً." },
    { q: "ما هي تكبيرات التشريق ومتى أقولها؟", a: "الله أكبر الله أكبر لا إله إلا الله والله أكبر الله أكبر ولله الحمد. بعد كل فريضة من فجر ٩ ذي الحجة إلى عصر ١٣." },
    { q: "هل يمكنني أكل لحم الأضحية؟", a: "نعم! كلوا ثلثاً، أهدوا ثلثاً، تصدقوا بثلث. السنة أن تأكلوا من أضحيتكم." },
    { q: "ماذا أفعل إذا أصابني ضربة شمس؟", a: "اذهبوا فوراً إلى الظل. اشربوا ماءً بارداً. بللوا الرأس والرقبة. اطلبوا المساعدة الطبية إذا تدهورت الحالة." },
    { q: "هل يمكنني ارتداء حزام أو حقيبة خصر في الإحرام؟", a: "نعم، الحزام وحقيبة الخصر والساعة والنظارات والنعال كلها مسموحة في الإحرام." },
    { q: "كيف أعرف اتجاه القبلة في عرفة ومنى؟", a: "استخدموا تطبيق بوصلة القبلة. في المسجد، اتبعوا صفوف المصلين. في الخيمة، اسألوا المرشد." }
  ],

